  /**
   * The model used for completion.
   */
  model: string;
  /**
   * The generated completion choices.
   */
  choices: Array<ChatCompletionChoice>;
  usage?: ChatCompletionUsage;
  /**
   * System fingerprint for the model configuration.
   */
